script:
if doc.pago == 1:
    doc.status = "Pago"
    frappe.db.set_value('Despesa do Brecho', doc.name, 'status', 'Pago')
    if not doc.data_pagamento:
        doc.data_pagamento = frappe.utils.nowdate()
        frappe.db.set_value('Despesa do Brecho', doc.name, 'data_pagamento', frappe.utils.nowdate())
else:
    doc.status = "Pendente"
    frappe.db.set_value('Despesa do Brecho', doc.name, 'status', 'Pendente')
